// Build a summary table for all quotations
const quotations = $input.all();
const rfqId = $node['Webhook: QCS Submitted'].json.body.rfqId;
const project = $node['Webhook: QCS Submitted'].json.body.project;
const budget = $node['Webhook: QCS Submitted'].json.body.budget;
const buyer = $node['Webhook: QCS Submitted'].json.body.buyer;
const qcsId = $node['Webhook: QCS Submitted'].json.body.qcsId;

// HTML-escape helper to prevent XSS in the generated email
function esc(str) {
  return String(str ?? '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#39;');
}

if (quotations.length === 0) {
  return [{ json: { tableHtml: '<p>No quotations found.</p>', rfqId, project, budget, buyer, qcsId } }];
}

const sorted = quotations
  .map(q => q.json)
  .sort((a, b) => (a.total_price || 0) - (b.total_price || 0));

const bestPrice = sorted[0];
const fastestDelivery = [...quotations.map(q => q.json)].sort((a, b) => (a.delivery_time || 99) - (b.delivery_time || 99))[0];

let rows = sorted.map((q, i) => {
  const tag = i === 0 ? ' ⭐ Best Price' : (q.supplier_id === fastestDelivery.supplier_id ? ' ⚡ Fastest Delivery' : '');
  return `<tr>
    <td>${esc(q.supplier_id)}${tag}</td>
    <td>€${(q.total_price || 0).toLocaleString()}</td>
    <td>${esc(q.delivery_time || '-')} weeks</td>
    <td>${esc(q.payment_terms || '-')}</td>
    <td>${esc(q.incoterms || '-')}</td>
  </tr>`;
}).join('');

const savings = budget - (bestPrice.total_price || 0);
const savingsPct = budget > 0 ? ((savings / budget) * 100).toFixed(1) : '0';

const tableHtml = `
<h3>Quotation Comparison – RFQ ${esc(rfqId)} (${esc(project)})</h3>
<table border='1' cellpadding='6' cellspacing='0' style='border-collapse:collapse;width:100%'>
  <thead style='background:#f0f0f0'>
    <tr><th>Supplier</th><th>Total Price</th><th>Delivery</th><th>Payment Terms</th><th>Incoterms</th></tr>
  </thead>
  <tbody>${rows}</tbody>
</table>
<br>
<p><strong>Budget:</strong> €${budget.toLocaleString()}</p>
<p><strong>Best Price:</strong> €${(bestPrice.total_price || 0).toLocaleString()} (${esc(bestPrice.supplier_id)})</p>
<p><strong>Potential Savings:</strong> €${savings.toLocaleString()} (${savingsPct}%)</p>
<p><strong>Fastest Delivery:</strong> ${esc(fastestDelivery.delivery_time)} weeks (${esc(fastestDelivery.supplier_id)})</p>
<p><strong>Buyer:</strong> ${esc(buyer)}</p>
<p><strong>QCS ID:</strong> ${esc(qcsId)}</p>
`;

return [{ json: { tableHtml, rfqId, project, budget, buyer, qcsId } }];
